using System.Collections;
using UnityEngine;

/// <summary>Para onde Action_FaceTarget vira o NPC.</summary>
public enum NpcFaceMode
{
    /// <summary>Vira para "target".</summary>
    Target,

    /// <summary>Vira para o player.</summary>
    Player,

    /// <summary>Vira para uma direção fixa (ver "direction").</summary>
    Direction
}

/// <summary>
/// Move o NPC horizontalmente até chegar perto de um alvo (ex: um "mark" da
/// cutscene, ou o player). Suspende o comportamento base de movimento
/// enquanto anda e espera chegar antes de continuar para a próxima ação.
/// </summary>
[System.Serializable]
public class Action_MoveToTarget : NpcAction
{
    [Tooltip("Para onde o NPC anda. Se vazio, usa a posição actual do player.")]
    public Transform target;

    [Tooltip("ID de outro NPC para onde andar (Etapa 8 — ver \"Npc Id\" no NpcController desse NPC). Se definido e encontrado, tem prioridade sobre \"target\".")]
    public string targetNpcId;

    [Tooltip("Velocidade do movimento (usa um valor baixo para \"andar\" e mais alto para \"correr\").")]
    public float speed = 2f;

    [Tooltip("Distância (eixo X) considerada \"chegou\".")]
    public float arriveDistance = 0.1f;

    [Tooltip("Tempo máximo de espera, em segundos (segurança, evita ficar preso para sempre se o alvo for inalcançável). 0 = sem limite.")]
    public float timeout = 5f;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement == null)
        {
            Debug.LogWarning($"[{npc.name}] Action_MoveToTarget: NpcMovement não encontrado.");
            yield break;
        }

        Transform fallback = target != null ? target : npc.Player;
        Transform t = NpcRefUtil.Resolve(targetNpcId, fallback);

        if (t == null)
        {
            Debug.LogWarning($"[{npc.name}] Action_MoveToTarget: nenhum alvo definido e o player não foi encontrado.");
            yield break;
        }

        yield return movement.MoveToPosition(t, speed, arriveDistance, timeout);
    }
}

/// <summary>Vira o NPC instantaneamente (flipX) para encarar um alvo, o player, ou uma direção fixa.</summary>
[System.Serializable]
public class Action_FaceTarget : NpcAction
{
    public NpcFaceMode mode = NpcFaceMode.Player;

    [Tooltip("Usado apenas quando Mode = Target.")]
    public Transform target;

    [Tooltip("Usado apenas quando Mode = Target (Etapa 8 — ver \"Npc Id\" no NpcController desse NPC). Se definido e encontrado, tem prioridade sobre \"target\".")]
    public string targetNpcId;

    [Tooltip("Usado apenas quando Mode = Direction. Positivo = direita, negativo = esquerda.")]
    public float direction = 1f;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement == null) yield break;

        switch (mode)
        {
            case NpcFaceMode.Target:
                var resolved = NpcRefUtil.Resolve(targetNpcId, target);
                if (resolved != null) movement.FaceTowards(resolved.position);
                break;

            case NpcFaceMode.Player:
                if (npc.Player != null) movement.FaceTowards(npc.Player.position);
                break;

            case NpcFaceMode.Direction:
                movement.FaceDirection(direction);
                break;
        }

        yield break;
    }
}

/// <summary>
/// Muda o comportamento base de movimento do NPC (Idle/FollowPlayer/FleePlayer/Patrol)
/// em runtime — útil para, por exemplo, um NPC começar Idle e passar a Patrol
/// depois de uma cutscene de apresentação.
/// </summary>
[System.Serializable]
public class Action_SetMovementMode : NpcAction
{
    public NpcMovementMode mode = NpcMovementMode.Idle;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement != null) movement.DefaultMode = mode;

        yield break;
    }
}

/// <summary>
/// Foge do player numa cutscene: corre na direção oposta ao player durante
/// "duration" segundos, recalculando a direção a cada passo de física (funciona
/// mesmo que o player se mova durante a fuga). Para uma fuga contínua "de fundo"
/// usa Action_SetMovementMode com mode = FleePlayer.
/// </summary>
[System.Serializable]
public class Action_FleeFromPlayer : NpcAction
{
    public float speed = 3f;
    public float duration = 1f;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement == null || npc.Player == null) yield break;

        yield return movement.FleeFromTransform(npc.Player, speed, duration);
    }
}

/// <summary>Faz o NPC saltar (impulso vertical no Rigidbody2D). Não faz nada se o NPC não estiver no chão.</summary>
[System.Serializable]
public class Action_Jump : NpcAction
{
    [Tooltip("Força vertical do salto (aplicada à velocidade do Rigidbody2D).")]
    public float force = 6f;

    [Tooltip("Se activo, espera o NPC voltar a tocar no chão antes de avançar para a próxima ação.")]
    public bool waitToLand = true;

    [Tooltip("Tempo máximo de espera por aterragem, em segundos (segurança). 0 = sem limite.")]
    public float timeout = 3f;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement == null) yield break;

        if (!movement.Jump(force)) yield break;

        if (waitToLand)
            yield return movement.WaitUntilGrounded(timeout);
    }
}

/// <summary>Espera até o player chegar a "distance" do NPC antes de continuar para a próxima ação.</summary>
[System.Serializable]
public class Action_WaitForPlayerNear : NpcAction
{
    [Tooltip("Distância à qual o player é considerado \"perto\".")]
    public float distance = 2f;

    [Tooltip("Tempo máximo de espera, em segundos (segurança). 0 = sem limite.")]
    public float timeout = 0f;

    public override IEnumerator Execute(NpcController npc)
    {
        if (npc.Player == null) yield break;

        float elapsed = 0f;

        while (Vector2.Distance(npc.Player.position, npc.transform.position) > distance)
        {
            elapsed += Time.deltaTime;
            if (timeout > 0f && elapsed >= timeout) yield break;
            yield return null;
        }
    }
}
